sql:
SELECT players.player_name, contracts.contract_value
FROM players
JOIN contracts ON players.player_id = contracts.player_id;

SELECT team_name 
FROM teams 
WHERE wins > (SELECT AVG(wins) FROM teams);

external_knowledge:
- 'standout athletes' refers to players whose salaries exceed the average total salary in playoff seasons;
- 'intense playoff games' refers to the playoff seasons ('season_type' = 'playoffs') in the NBA;
- 'above-average paychecks' mean the total salary is greater than the average total salary across all seasons.

sql:
SELECT p.player_id, p.player_name, s.base_salary
FROM players p
JOIN salaries s ON p.player_id = s.player_id
WHERE s.base_salary = (
    SELECT MAX(base_salary) FROM salaries
);

external_knowledge:
- "base pay" refers to the base_salary;
- "extra earnings" refers to the bonuses;
- "overall earnings" refers to the total_salary;
